#include "jit.h"
#include <stdio.h>
#include <string.h>
#define CHECK(x) do{if(!(x)){fprintf(stderr,"check failed: %s:%d: %s\n",__FILE__,__LINE__,#x);return 1;}}while(0)
static int make_add(TurboJSIRFunction*f){TurboJSIRInstruction in;uint16_t a,k,r;TurboJS_IRFunctionInit(f,1);a=TurboJS_IRAllocateRegister(f);k=TurboJS_IRAllocateRegister(f);r=TurboJS_IRAllocateRegister(f);memset(&in,0,sizeof(in));in.opcode=TURBOJS_IR_ARGUMENT;in.destination=a;CHECK(TurboJS_IREmit(f,in)==TURBOJS_IR_OK);in.opcode=TURBOJS_IR_CONSTANT_I64;in.destination=k;in.immediate=1;CHECK(TurboJS_IREmit(f,in)==TURBOJS_IR_OK);in.opcode=TURBOJS_IR_ADD_I64;in.destination=r;in.left=a;in.right=k;CHECK(TurboJS_IREmit(f,in)==TURBOJS_IR_OK);in.opcode=TURBOJS_IR_RETURN_I64;in.left=r;CHECK(TurboJS_IREmit(f,in)==TURBOJS_IR_OK);return 0;}
int main(void){TurboJSIRFunction f;TurboJSAOTModuleFunction mf;TurboJSAOTBuffer image={0};TurboJSAOTModule module={0};TurboJSAOTLoadLimits limits;TurboJSIRDiagnostic d;CHECK(make_add(&f)==0);mf.name="increment";mf.ir=&f;CHECK(TurboJS_AOTSerializeModule(&mf,1,&image,&d)==TURBOJS_IR_OK);limits=TurboJS_AOTLoadLimitsDefault();limits.max_image_bytes=image.size-1;CHECK(TurboJS_AOTDeserializeModuleWithLimits(image.data,image.size,&limits,&module,&d)!=TURBOJS_IR_OK);limits=TurboJS_AOTLoadLimitsDefault();limits.max_function_count=0;CHECK(TurboJS_AOTDeserializeModuleWithLimits(image.data,image.size,&limits,&module,&d)!=TURBOJS_IR_OK);limits=TurboJS_AOTLoadLimitsDefault();limits.max_name_bytes=3;CHECK(TurboJS_AOTDeserializeModuleWithLimits(image.data,image.size,&limits,&module,&d)!=TURBOJS_IR_OK);limits=TurboJS_AOTLoadLimitsDefault();limits.max_instructions_per_function=3;CHECK(TurboJS_AOTDeserializeModuleWithLimits(image.data,image.size,&limits,&module,&d)!=TURBOJS_IR_OK);limits=TurboJS_AOTLoadLimitsDefault();limits.max_total_instructions=3;CHECK(TurboJS_AOTDeserializeModuleWithLimits(image.data,image.size,&limits,&module,&d)!=TURBOJS_IR_OK);limits=TurboJS_AOTLoadLimitsDefault();CHECK(TurboJS_AOTDeserializeModuleWithLimits(image.data,image.size,&limits,&module,&d)==TURBOJS_IR_OK);CHECK(module.function_count==1);TurboJS_AOTModuleDestroy(&module);TurboJS_AOTBufferDestroy(&image);TurboJS_IRFunctionDestroy(&f);puts("AOT loader resource limits passed");return 0;}
